
ON CONFLICT (code) DO UPDATE SET
  phase = EXCLUDED.phase,
  subtitle = EXCLUDED.subtitle,
  sort_order = EXCLUDED.sort_order,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  icon = EXCLUDED.icon,
  reward_type = EXCLUDED.reward_type,
  reward_amount = EXCLUDED.reward_amount;

-- Update legacy milestones with phases
UPDATE milestones SET phase = 'discover' WHERE code IN ('complete_profile', 'add_spoken_languages', 'join_first_guild', 'join_creative_circle', 'impact_guild');
UPDATE milestones SET phase = 'contribute' WHERE code IN ('collaborate_pod', 'contribute_territory', 'attend_event', 'impact_territory_memory');
UPDATE milestones SET phase = 'create' WHERE code IN ('create_first_quest', 'publish_service', 'publish_course', 'creative_artwork_quest', 'creative_class', 'impact_quest', 'host_workshop');
UPDATE milestones SET phase = 'structure' WHERE code IN ('become_shareholder', 'invite_friend');
